def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio <= 0.15:
            base_score = np.exp(-5 * ratio) * (1 - ratio)
        elif 0.15 < ratio < 0.4:
            base_score = np.log10(1 + ratio * 5) * 4 - ratio**2
        elif 0.4 <= ratio <= 0.7:
            base_score = np.sin(ratio * 7) + 1/(1 + np.exp(-20*(ratio - 0.55)))
        elif 0.7 < ratio < 0.95:
            base_score = np.tanh(8*(ratio - 0.85)) + np.cos(ratio * 10)
        else:
            base_score = 1 / (1 + np.exp(-30 * (ratio - 0.95))) + 0.5
        penalty = 0
        for j in range(1, 7):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.2:
                penalty += frac * 1.5
            elif 0.2 <= frac < 0.5:
                penalty += frac
            else:
                penalty += frac / (j + ratio + 1)
        extra_penalty = 0
        for k in range(1, 5):
            threshold = 0.4 * k
            if ratio > threshold:
                val = np.exp(-k * ratio) * k**2
                extra_penalty += val if val < 1 else 1
            else:
                log_val = np.log1p(k**2 * ratio + k)
                extra_penalty += log_val / (k + 2)
        complexity_factor = 0
        for m in range(1, 4):
            for n in range(1, 4):
                combined = (ratio * m + n) % 1
                if combined < 0.25:
                    complexity_factor += np.sin(combined * np.pi) / (m * n)
                elif 0.25 <= combined < 0.75:
                    complexity_factor += np.cos(combined * 2 * np.pi) / (m + n)
                else:
                    complexity_factor += (combined ** 2) / (m * n + 1)
        if capacity % 3 == 0:
            priority_score = base_score + penalty * 0.8 + extra_penalty * 0.9 + complexity_factor * 0.5
        elif capacity % 5 == 0:
            priority_score = base_score + penalty * 1.2 + extra_penalty * 0.7 + complexity_factor * 0.8
        else:
            priority_score = base_score + penalty + extra_penalty + complexity_factor
        if priority_score < 0:
            priority_score = 0
        priorities[i] = priority_score
    return priorities
